VALUES
  ('dietitian-moex-08484', 'dietitian', 'dietitian-moex-098-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '某中年婦女身高約158公分，體重約50公斤，日常活動以靜態為主。每日身體活動以散步、購物為主， 且不超過一小時。根據行政院衛生署所定「國人膳食營養素參考攝取量，DRIs」之建議，該婦女之每日 熱量建議攝取量應約為：', '["1200大卡", "1500大卡", "1800大卡", "2000大卡"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "3add4eefe485", "answer_pdf_sha1": "7ce9b6bd0e76", "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 36, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08485', 'dietitian', 'dietitian-moex-098-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '近年國人肥胖盛行率日漸增加，根據行政院衛生署所訂定之「成人肥胖定義及處理原則」乃使用下列那', '["腰臀比", "體脂肪", "身體質量指數", "腰圍"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "3add4eefe485", "answer_pdf_sha1": "7ce9b6bd0e76", "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 37, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08486', 'dietitian', 'dietitian-moex-098-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '目前世界衛生組織建議各國之飲食指標應以何者為建議基礎？', '["食物", "營養素", "疾病預防", "抗氧化物質"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "3add4eefe485", "answer_pdf_sha1": "7ce9b6bd0e76", "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 38, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08487', 'dietitian', 'dietitian-moex-098-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '陳小姐目前準備懷孕，她想知道自己的葉酸營養狀況是否合宜，因此抽血檢查，若其血漿葉酸濃度為', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "3add4eefe485", "answer_pdf_sha1": "7ce9b6bd0e76", "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 39, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08488', 'dietitian', 'dietitian-moex-098-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', 'ng/mL，則其葉酸營養狀況屬於那一種狀況？', '["葉酸營養狀況正常", "葉酸臨界缺乏", "葉酸缺乏", "無法判別"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "3add4eefe485", "answer_pdf_sha1": "7ce9b6bd0e76", "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 5, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08489', 'dietitian', 'dietitian-moex-098-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '以老人送餐為題材，下列何者最易導致社會健康均衡性失調？', '["對中低收入戶補助而不補助一般所得者", "偏遠地區與城市地區補助款額度相同", "政府財源不足，僅設計補助三年老人送餐", "未依照老人營養與口味需求評估後給予個人化飲食"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "3add4eefe485", "answer_pdf_sha1": "7ce9b6bd0e76", "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 40, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08490', 'dietitian', 'dietitian-moex-098-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '美美餐館辦理600人次自助餐會，設計每人平均50 g美國生菜（Lettuces），而其產出率為75％，請計算 應採購多少公斤美國生菜？', '["30", "35", "40", "45"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "4ba10aa76df7", "answer_pdf_sha1": "07d310bd3799", "source_family": "moex-gov-tw", "moex": {"exam_code": "098020", "c": "113", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "098", "exam_name": "098年第一次專技醫事人員、中醫師、心理師、營養師、醫師分試", "original_question_number": 1, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08491', 'dietitian', 'dietitian-moex-098-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '關於團膳供應常用餐具材質與規格敘述，何者正確？', '["美耐皿（Melamine）質地非常堅硬，頗受餐飲業歡迎", "相同規格餐具中以聚丙烯（polypropylene）材質最便宜", "聚碳酸鹽（polycarbonate）飯碗耐冷溫度為0℃", "瓷器餐具耐腐蝕、保溫性強"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "4ba10aa76df7", "answer_pdf_sha1": "07d310bd3799", "source_family": "moex-gov-tw", "moex": {"exam_code": "098020", "c": "113", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "098", "exam_name": "098年第一次專技醫事人員、中醫師、心理師、營養師、醫師分試", "original_question_number": 2, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08492', 'dietitian', 'dietitian-moex-098-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '下列有關循環菜單敘述，何者有誤？', '["剩菜易處理", "便於在產品採購、生產與銷售上進行標準化管理", "循環週期宜因地制宜，因人而異", "不能迅速地適應市場需求的變化"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "4ba10aa76df7", "answer_pdf_sha1": "07d310bd3799", "source_family": "moex-gov-tw", "moex": {"exam_code": "098020", "c": "113", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "098", "exam_name": "098年第一次專技醫事人員、中醫師、心理師、營養師、醫師分試", "original_question_number": 3, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08493', 'dietitian', 'dietitian-moex-098-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '根據勞動基準法第38條，勞工在同一雇主或事業單位，繼續工作滿一年以上三年未滿者，每年應依規定 給予幾天特別休假？', '["4", "7", "10", "14"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "4ba10aa76df7", "answer_pdf_sha1": "07d310bd3799", "source_family": "moex-gov-tw", "moex": {"exam_code": "098020", "c": "113", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "098", "exam_name": "098年第一次專技醫事人員、中醫師、心理師、營養師、醫師分試", "original_question_number": 4, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
